const today = new Date().toISOString().split('T')[0];
const todayDate = new Date();
const nextWeek = new Date(Date.now() + 7*86400000).toISOString().split('T')[0];

// Calculate week-of string (Monday of current week)
const dayOfWeek = todayDate.getDay();
const daysToMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
const monday = new Date(todayDate.getTime() - daysToMonday * 86400000);
const weekOf = monday.toISOString().split('T')[0];

let mtl = '';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  mtl = buf.toString('utf-8');
} catch(e) {}

const areas = ['faith','family','business','consulting','work','health','home','personal'];
const stats = {};
for (const a of areas) stats[a] = { total: 0, completed: 0, overdue: 0, dueThisWeek: 0, noDue: 0, priorityA: 0 };

// Parse open tasks — single-escape regex per canonical pattern
const openRe = /^- \[ \] (.+?)\[area:: (\w+)\].*?\[priority:: ([ABC])\](?:.*?\[due:: (\d{4}-\d{2}-\d{2})\])?/gm;
let m;
while ((m = openRe.exec(mtl)) !== null) {
  const [, desc, area, priority, due] = m;
  if (!stats[area]) continue;
  stats[area].total++;
  if (priority === 'A') stats[area].priorityA++;
  if (!due) {
    stats[area].noDue++;
  } else {
    if (due < today) stats[area].overdue++;
    if (due >= today && due <= nextWeek) stats[area].dueThisWeek++;
  }
}

// Parse completed tasks
const doneRe = /^- \[x\] (.+?)\[area:: (\w+)\]/gm;
while ((m = doneRe.exec(mtl)) !== null) {
  const [, , area] = m;
  if (stats[area]) stats[area].completed++;
}

// Week Health Score
const totalOverdue = areas.reduce((s, a) => s + stats[a].overdue, 0);
const totalNoDue   = areas.reduce((s, a) => s + stats[a].noDue, 0);
const overdueP     = Math.min(5, totalOverdue);
const noDueScore   = totalNoDue === 0 ? 10 : Math.max(0, 10 - Math.min(10, totalNoDue));
const healthScore  = Math.max(0, noDueScore - overdueP);
const scoreColor   = healthScore >= 8 ? '#16a34a' : healthScore >= 5 ? '#d97706' : '#dc2626';

// Q2 Rock progress (hardcoded values)
const q2Rocks = [
  { area: 'faith',    label: 'Launch social media Bible study (4 sessions)', pct: 35, color: '#7c3aed' },
  { area: 'family',   label: 'Marriage Alignment Questionnaire + bi-weekly check-in', pct: 0, color: '#db2777' },
  { area: 'business', label: 'Ship MVP — website, offer, 3 outreach (Echelon Seven)', pct: 25, color: '#0284c7' },
  { area: 'work',     label: 'Deliver Union project + position for exit', pct: 0, color: '#0891b2' },
  { area: 'health',   label: 'Hip decision + 3x/week gym for 8 weeks', pct: 0, color: '#16a34a' },
];

function areaRowColor(overdue) {
  if (overdue === 0) return '#f0fdf4';
  if (overdue <= 2) return '#fffbeb';
  return '#fef2f2';
}
function areaRowBorder(overdue) {
  if (overdue === 0) return '#86efac';
  if (overdue <= 2) return '#fcd34d';
  return '#fca5a5';
}

// Focus: top 3 Priority A tasks with no due date
const undatedRocks = [];
const allARe = /^- \[ \] (.+?)\[area:: (\w+)\].*?\[priority:: ([ABC])\](?:.*?\[due:: (\d{4}-\d{2}-\d{2})\])?/gm;
while ((m = allARe.exec(mtl)) !== null) {
  const [, desc, area, priority, due] = m;
  if (priority === 'A' && !due && undatedRocks.length < 3) {
    undatedRocks.push({ desc: desc.trim(), area });
  }
}

let areaRows = '';
for (const area of areas) {
  const s = stats[area];
  if (s.total + s.completed === 0) continue;
  const bg = areaRowColor(s.overdue);
  const bdr = areaRowBorder(s.overdue);
  const overdueBadge = s.overdue > 0
    ? `<span style="background:${s.overdue >= 3 ? '#dc2626' : '#f59e0b'};color:white;padding:1px 6px;border-radius:3px;font-size:11px">${s.overdue} overdue</span>`
    : `<span style="color:#16a34a;font-size:12px">✓ none</span>`;
  areaRows += `<tr style="background:${bg};border-left:4px solid ${bdr}">
    <td style="padding:8px 12px;font-weight:bold;text-transform:capitalize">${area}</td>
    <td style="padding:8px;text-align:center">${s.total}</td>
    <td style="padding:8px;text-align:center;color:#16a34a">${s.completed}</td>
    <td style="padding:8px;text-align:center">${s.priorityA}</td>
    <td style="padding:8px;text-align:center">${s.dueThisWeek}</td>
    <td style="padding:8px;text-align:center">${overdueBadge}</td>
  </tr>`;
}

let rockRows = '';
for (const r of q2Rocks) {
  const pctLabel = r.pct === 0 ? 'Not started' : `${r.pct}%`;
  const barFill = r.pct > 0 ? `<div style="background:${r.color};height:8px;border-radius:4px;width:${r.pct}%"></div>` : '';
  rockRows += `<tr>
    <td style="padding:10px 12px;font-weight:bold;text-transform:capitalize;color:${r.color}">${r.area}</td>
    <td style="padding:10px 12px">${r.label}</td>
    <td style="padding:10px 12px;min-width:120px">
      <div style="background:#e5e7eb;border-radius:4px;height:8px;margin-bottom:4px">${barFill}</div>
      <span style="font-size:11px;color:#6b7280">${pctLabel}</span>
    </td>
  </tr>`;
}

let focusRows = '';
if (undatedRocks.length === 0) {
  focusRows = '<tr><td colspan="3" style="padding:12px;color:#16a34a">All Priority A tasks have due dates scheduled. Nice work!</td></tr>';
} else {
  for (const r of undatedRocks) {
    focusRows += `<tr>
      <td style="padding:8px 12px;text-transform:capitalize;color:#7c3aed;font-weight:bold">${r.area}</td>
      <td style="padding:8px 12px">${r.desc}</td>
      <td style="padding:8px 12px"><span style="background:#f3f4f6;color:#6b7280;padding:2px 8px;border-radius:3px;font-size:11px">needs date</span></td>
    </tr>`;
  }
}

const html = `
<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#f5f5f5;padding:20px">
  <div style="background:#1a1a2e;color:white;padding:20px;border-radius:8px 8px 0 0">
    <h1 style="margin:0;font-size:22px">&#128202; Weekly Life OS Review</h1>
    <p style="margin:5px 0 0;opacity:0.8">Week of ${weekOf} &middot; Generated ${today}</p>
  </div>
  <div style="background:${scoreColor};color:white;padding:12px 20px;margin:2px 0;text-align:center">
    <span style="font-size:28px;font-weight:bold">${healthScore}/10</span>
    <span style="margin-left:12px;opacity:0.9;font-size:16px">Weekly Health Score</span>
    <div style="margin-top:4px;font-size:12px;opacity:0.8">${totalOverdue} overdue &middot; ${totalNoDue} undated open tasks</div>
  </div>
  <div style="background:white;padding:20px;margin:2px 0">
    <h2 style="margin:0 0 12px;font-size:16px;color:#1a1a2e">&#128202; Area Health Summary</h2>
    <table style="width:100%;border-collapse:collapse;font-size:13px">
      <thead><tr style="background:#1a1a2e;color:white">
        <th style="padding:8px 12px;text-align:left">Area</th>
        <th style="padding:8px;text-align:center">Open</th>
        <th style="padding:8px;text-align:center">Done</th>
        <th style="padding:8px;text-align:center">A</th>
        <th style="padding:8px;text-align:center">Due 7d</th>
        <th style="padding:8px;text-align:center">Overdue</th>
      </tr></thead>
      <tbody>${areaRows}</tbody>
    </table>
    <p style="margin:8px 0 0;font-size:11px;color:#9ca3af">Green = no overdue &middot; Amber = 1-2 overdue &middot; Red = 3+ overdue</p>
  </div>
  <div style="background:white;padding:20px;margin:2px 0">
    <h2 style="margin:0 0 12px;font-size:16px;color:#1a1a2e">&#127873; Q2 2026 Rock Progress</h2>
    <table style="width:100%;border-collapse:collapse;font-size:13px"><tbody>${rockRows}</tbody></table>
  </div>
  <div style="background:white;padding:20px;margin:2px 0">
    <h2 style="margin:0 0 8px;font-size:16px;color:#1a1a2e">&#127919; Focus for Next Week — Undated Priority A Rocks</h2>
    <p style="margin:0 0 12px;font-size:12px;color:#6b7280">These Priority A tasks have no due date. Schedule them this week.</p>
    <table style="width:100%;border-collapse:collapse;font-size:13px"><tbody>${focusRows}</tbody></table>
  </div>
  <div style="background:#374151;color:white;padding:12px 20px;border-radius:0 0 8px 8px;text-align:center;font-size:11px">
    Life OS Weekly Review &middot; ${today} &middot; ObsidianHomeOrchestrator
  </div>
</div>`.trim();

return [{ json: { html, subject: `Weekly Life OS Review — Week of ${weekOf}`, today, weekOf } }];

const today = new Date().toISOString().split('T')[0];
const log = JSON.stringify({
  workflow: 'weekly-digest-v2',
  run_date: today,
  status: 'success',
  generated_at: new Date().toISOString()
}, null, 2);
return [{ json: { logKey: `99_System/logs/weekly-digest-${today}.json`, logContent: log } }];

const content = $json.logContent;
const key = $json.logKey;
const buf = Buffer.from(content, 'utf-8');
return [{ json: $json, binary: { data: { data: buf.toString('base64'), mimeType: 'application/json', fileName: key.split('/').pop(), fileExtension: 'json', fileSize: buf.length } } }];
